using System;
using System.Runtime.InteropServices;
using SkiaSharp;

SKImageInfo imageInfo = new(1, 1, SKColorType.Alpha8);
var color = new SKColor(25, 0, 0, 50);

// CPU baseline
using var bitmap = new SKBitmap(imageInfo);
using var canvas = new SKCanvas(bitmap);
canvas.Clear(color);
Console.WriteLine($"Bitmap Alpha8: {bitmap.Bytes[0]}");

// CPU Surface
using var cpuSurface = SKSurface.Create(imageInfo);
cpuSurface.Canvas.Clear(color);
using var cpuPixmap = cpuSurface.PeekPixels();
Console.WriteLine($"CPU Surface Alpha8: {cpuPixmap.GetPixelSpan()[0]}");

// GPU Surface via CGL
int[] attribs = new int[] { 0 };
CGLChoosePixelFormat(attribs, out var pf, out _);
CGLCreateContext(pf, IntPtr.Zero, out var ctx);
CGLSetCurrentContext(ctx);
using var gli = GRGlInterface.Create();
using var grCtx = GRContext.CreateGl(gli);
using var gpuSurface = SKSurface.Create(grCtx, false, imageInfo);
gpuSurface.Canvas.Clear(color);
gpuSurface.Canvas.Flush();
gpuSurface.Flush(true, true);
using var gpuImage = gpuSurface.Snapshot();
using var gpuBitmap = SKBitmap.FromImage(gpuImage);
Console.WriteLine($"GPU Bitmap: {string.Join(", ", gpuBitmap.Bytes)}");

[DllImport("/System/Library/Frameworks/OpenGL.framework/OpenGL")]
static extern int CGLChoosePixelFormat(int[] a, out IntPtr p, out int n);
[DllImport("/System/Library/Frameworks/OpenGL.framework/OpenGL")]
static extern int CGLCreateContext(IntPtr p, IntPtr s, out IntPtr c);
[DllImport("/System/Library/Frameworks/OpenGL.framework/OpenGL")]
static extern int CGLSetCurrentContext(IntPtr c);
